import React from 'react';

const scrollTo = (id) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });

function Hero() {
  return (
    <section id="home" className="hero">
      <div className="hero-content">
        <p className="tag">✦ Maldives · Est. 2008 ✦</p>
        <h1>Where Luxury<br /><em>Meets the Sea</em></h1>
        <p className="desc">
          A peaceful getaway with luxury rooms, scenic ocean views,
          and world-class hospitality on the shores of the Maldives.
        </p>
        <div className="hero-btns">
          <button className="btn-gold" onClick={() => scrollTo('rooms')}>Explore Rooms</button>
          <button className="btn-outline" onClick={() => scrollTo('contact')}>Book a Stay</button>
        </div>
      </div>
    </section>
  );
}

export default Hero;
